// Script Continued Below
// STRY0074673
function onSubmit() {
	var table = 'x_153465_discovert_organizational_contacts';

	// NOTE: the first story to use this is related to external outboud contacts.
	// The initial implementation sets the parent to the External Outbout OU to support this case
	// Additional stories will need to set this based on the task, the top task settings and the bottom task settings.
	// the OU should map to the contacts being displayed for that task.
	var defaultContactOU = '';
	try{

		if(g_form.getActionName() == 'TemplateTask_add_contact'){
			// default in order of prescedence.  TA as top precedence, then External, then Primary Assignee
			// NOTE: could add 3 different actions for each type of Contact add with a submenu
			if((g_form.getValue('primary_assignee') + '' != '')) {
				defaultContactOU = g_form.getValue('primary_assignee');
			}
			if(g_form.getValue('u_external_ou') + '' != '') {
				defaultContactOU = g_form.getValue('u_external_ou');
			}
			if((g_form.getValue('tasking_authority') + '' != '') && g_form.getValue('tasking_authority.u_external_flag') == 'true') {
				defaultContactOU = g_form.getValue('tasking_authority');
			}
			if (typeof spModal != 'undefined' ) {
				spModal.open({
					title: 'Add Organizational Contact',
					message:'',
					backdrop:'static',
					widget: 'discovertasker-formtab',
					widgetInput: {
						table: table,
						sys_id: -1,
						view:'sp',
						isModal: true,
						query: 'u_contact_ou=' + defaultContactOU
					},
					size:'lg',
					buttons: [],
					// 2.7.2 | 2022-01-13 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
					footerStyle: {
						'display': 'none'
					}
				});
			} else {
				// STRY0074673
				//the values from the sysparm_query initialize the default values in the GlideModalForm

				//GlideModalForm displays a form as a modal
				//the addParm function takes the values from the record and initializes the form fields to the specified values
				//if any of the fields is not included in addParm query that field will not be editable in the modal
				var modalForm = new GlideModalForm('Add Organizational Contact', 'x_153465_discovert_organizational_contacts');
				modalForm.addParm('sysparm_query','u_contact_ou='+defaultContactOU);
				modalForm.render();
				modalForm.setSysID(-1);

			}
			return false;
		}
	}catch(e){
		jslog (e);
		return false;
	}
}
